const body = $input.first().json.body || $input.first().json || {};
const niche = (body.niche || '').trim();
const city = (body.city || '').trim();
const type = (body.target_audience_type || 'B2C').trim().toUpperCase();
const project_id = (body.project_id || '').trim();
const domain = (body.domain || '').trim();
const niche_cluster = (body.niche_cluster || 'commercial_local').trim();
const priority_engines = (body.priority_engines || 'both').trim();
const is_cron = $execution.mode === 'trigger';

// Strict validation
const errors = [];
if (!niche) errors.push('niche is required');
if (!city) errors.push('city is required');
if (!['B2C', 'B2B', 'B2B2C'].includes(type)) errors.push('target_audience_type must be B2C/B2B/B2B2C');
if (!project_id) errors.push('project_id is required');

if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join('; '));
}

// Deterministic ID for deduplication
const crypto = require('crypto');
const dedup_key = `${project_id}_${niche}_${city}_${type}`.toLowerCase();
const deterministic_id = crypto.createHash('md5').update(dedup_key).digest('hex');

// Deterministic A/B via hash instead of Math.random()
const ab_hash = parseInt(crypto.createHash('md5').update(project_id + niche).digest('hex').substring(0, 8), 16);
const ab_bucket = ab_hash % 3;

return [{ json: {
  niche, city, target_audience_type: type, project_id, domain,
  niche_cluster, priority_engines,
  embed_query: `${niche} ${city} ${type} целевая аудитория SEO анализ`,
  is_cron_trigger: is_cron,
  dedup_key,
  deterministic_id,
  ab_bucket,
  attempt: 1,
  best_qc: 0,
  best_persona: null
}}];

let pResults = [], cResults = [], iResults = [];
try { pResults = $('Search seo_personas2').first().json.result || []; } catch(e) {}
try { cResults = $('Search competitor_audiences').first().json.result || []; } catch(e) {}
try { iResults = $('Search search_intents').first().json.result || []; } catch(e) {}

let context = '', sourcesCount = 0;

if (pResults.length > 0) {
  context += '=== ПОХОЖИЕ ПЕРСОНЫ ИЗ БАЗЫ (RAG) ===\n\n';
  pResults.forEach((r, i) => {
    const p = r.payload || {};
    context += `Проект ${i+1} (релевантность: ${Math.round(r.score*100)}%):\n`;
    context += `  Ниша: ${p.niche||''}, город: ${p.city||''}\n`;
    context += `  Персона: ${p.persona_name||''}\n`;
    context += `  JTBD: ${p.main_jtbd||'н/д'}\n`;
    context += `  QC: ${p.qc_score||'н/д'}/100\n---\n`;
  });
  sourcesCount += pResults.length;
}

if (cResults.length > 0) {
  context += '\n=== ДАННЫЕ О ЦА КОНКУРЕНТОВ ===\n\n';
  cResults.forEach((r, i) => {
    const c = r.payload || {};
    context += `Конкурент ${i+1}: ${c.competitor_domain||''}\n`;
    context += `  Сегмент: ${c.segment||'н/д'}\n`;
    context += `  Ключевые отличия: ${c.differentiators||'н/д'}\n---\n`;
  });
  sourcesCount += cResults.length;
}

if (iResults.length > 0) {
  context += '\n=== МАППИНГ SEARCH INTENT ===\n\n';
  iResults.forEach((r) => {
    const s = r.payload || {};
    context += `${s.query||''} → ${s.intent_type||''} (Хант: ${s.hunt_level||''}, Volume: ${s.volume||'н/д'})\n`;
  });
  sourcesCount += iResults.length;
}

return [{ json: {
  rag_context: context || 'Нет данных в RAG базе — генерация с нуля.',
  sources_count: sourcesCount,
  top_score: pResults[0]?.score || 0,
  has_competitor_data: cResults.length > 0,
  has_intent_data: iResults.length > 0,
  rag_quality: sourcesCount >= 5 ? 'rich' : (sourcesCount > 0 ? 'partial' : 'empty')
}}];

const rag = $('Format RAG Context').first().json;
const inp = $('Validate & Normalize Input').first().json;

// Deterministic A/B via hash (not Math.random)
const abBucket = inp.ab_bucket;
const attempt = inp.attempt || 1;

// On retry: rotate strategy
const effectiveBucket = (abBucket + attempt - 1) % 3;

let abVersion, promptStrategy;
if (effectiveBucket === 0) {
  abVersion = 'v4.0_A_structured';
  promptStrategy = 'СТРУКТУРИРОВАННЫЙ ПОДХОД: Начни с анализа рынка, затем построй персону. Используй фреймворк JTBD + Лестница Ханта последовательно.';
} else if (effectiveBucket === 1) {
  abVersion = 'v4.0_B_empathy';
  promptStrategy = 'ЭМПАТИЧЕСКИЙ ПОДХОД: Начни с болей и эмоций аудитории. Погрузись в мир персоны, затем формализуй через JTBD и поисковое поведение.';
} else {
  abVersion = 'v4.0_C_data_driven';
  promptStrategy = 'DATA-DRIVEN ПОДХОД: Начни с поисковых запросов и данных конкурентов. Построй персону на основе реального поискового поведения и intent mapping.';
}

if (attempt > 1) abVersion += `_retry${attempt}`;

const ragBlock = rag.rag_context
  ? `\n\nКОНТЕКСТ ИЗ RAG БАЗЫ (качество: ${rag.rag_quality}, ${rag.sources_count} источников):\n${rag.rag_context}\n\nИспользуй данные RAG для обогащения, но НЕ копируй буквально. Адаптируй под текущую нишу и город.`
  : '';

const engineSplit = inp.priority_engines === 'both'
  ? `\n\nОБЯЗАТЕЛЬНО: Для КАЖДОГО поискового запроса указывай поле "engine": "yandex" | "google" | "both".
- [Я] Яндекс-специфичные запросы: с городом, «рядом», «рейтинг», «отзывы», разговорные
- [G] Google-специфичные: англицизмы, «best», «vs», «review», длинные информационные  
- [ОБА] Универсальные: общие коммерческие запросы`
  : '';

const systemPrompt = `Ты — Senior маркетолог-аналитик с 15-летним опытом в digital-маркетинге и SEO.

ТВОЯ СПЕЦИАЛИЗАЦИЯ:
- Jobs-To-Be-Done (JTBD) framework — функциональные, эмоциональные, социальные работы
- Лестница осведомлённости Бена Ханта (5 уровней)
- AEO (Answer Engine Optimization) — оптимизация под AI-поиск
- GEO (Generative Engine Optimization) — оптимизация под генеративные системы
- YMYL-тематики и E-E-A-T факторы

СТРАТЕГИЯ ГЕНЕРАЦИИ: ${promptStrategy}
${ragBlock}

КРИТИЧЕСКИЕ ПРАВИЛА:
1) Создай ОДНУ детальную персону
2) Все данные должны быть РЕАЛИСТИЧНЫМИ для указанного региона
3) Поисковые запросы строго на РУССКОМ языке
4) JTBD формулируй от первого лица: "Когда я [ситуация], я хочу [действие], чтобы [результат]"
5) AEO-профиль ОБЯЗАТЕЛЕН: включи AI-поиск (Яндекс Нейро, ChatGPT, Perplexity)
6) Минимум 5000 символов в ответе
7) Каждый уровень Ханта = минимум 3 поисковых запроса
8) Каждый запрос содержит поле "engine" для указания поисковой системы${engineSplit}

ФОРМАТ: Ответь строго валидным JSON без markdown-обёртки, без комментариев, без trailing commas.
Prompt version: ${abVersion}`;

const userPrompt = `Создай детальный портрет целевой аудитории:

ВХОДНЫЕ ДАННЫЕ:
- НИША: ${inp.niche}
