  },
  "commercial_factors": {
    "price_sensitivity": "низкая|средняя|высокая",
    "avg_check_range": "от X до Y руб.",
    "payment_preferences": ["онлайн", "наличные", "рассрочка"],
    "seasonal_patterns": ["пик 1", "спад 1"]
  },
  "priority_score": 85,
  "priority_reasoning": "обоснование приоритетности сегмента"
