return [{ json: {
  system_prompt: systemPrompt,
  user_prompt: userPrompt,
  prompt_version: abVersion,
  model: 'llama-3.3-70b-versatile',
  fallback_model: 'llama-3.1-8b-instant',
  attempt: inp.attempt || 1
}}];

const p = $('Build Prompt v4.0').first().json;
const inp = $('Validate & Normalize Input').first().json;

const logEntry = {
  workflow_name: 'NN_00_v4.0_PRO',
  workflow_id: 'step_00',
  project_id: inp.project_id,
  prompt_version: p.prompt_version,
  prompt_type: 'persona_generation',
  model: p.model,
  system_prompt: p.system_prompt.substring(0, 3000),
  user_prompt: p.user_prompt.substring(0, 3000),
  input_data: JSON.stringify({niche: inp.niche, city: inp.city, type: inp.target_audience_type, domain: inp.domain, cluster: inp.niche_cluster}),
  attempt: p.attempt || 1,
  status: 'pending',
  started_at: new Date().toISOString()
};

return [{ json: { llm_log_payload: logEntry, prompt_version: p.prompt_version }}];

const prompt = $('Build Prompt v4.0').first().json;
const preLog = $('Save LLM Log (Pre)').first().json;
const logId = preLog.Id || preLog.id || null;

const payload = {
  model: prompt.model,
  max_tokens: 5000,
  temperature: 0.4,
  top_p: 0.9,
  response_format: { type: "json_object" },
  messages: [
    { role: 'system', content: prompt.system_prompt },
    { role: 'user', content: prompt.user_prompt }
  ]
};

return [{ json: {
  groq_payload: payload,
  fallback_model: prompt.fallback_model,
  log_id: logId,
  attempt: prompt.attempt || 1,
  started_at: Date.now()
}}];

const response = $input.first().json;
const inp = $('Validate & Normalize Input').first().json;
const ragInfo = $('Format RAG Context').first().json;
const promptInfo = $('Build Prompt v4.0').first().json;
const llmPrep = $('Prepare LLM Call').first().json;
const latency_ms = Date.now() - llmPrep.started_at;

let rawText = '', tokens = 0, model_used = '';
if (response.choices) {
  rawText = response.choices[0].message.content;
  tokens = response.usage?.total_tokens || 0;
  model_used = response.model || '';
} else if (response.content) {
  rawText = response.content[0].text;
} else {
  throw new Error('Unknown LLM response format: ' + JSON.stringify(response).substring(0, 200));
}

// Robust JSON extraction
let clean = rawText;
clean = clean.replace(/^```(?:json)?\s*\n?/gm, '').replace(/\n?```\s*$/gm, '').trim();
clean = clean.replace(/^\uFEFF/, '');

const jsonMatch = clean.match(/\{[\s\S]*\}/);
if (jsonMatch) clean = jsonMatch[0];

clean = clean.replace(/,\s*([}\]])/g, '$1');
clean = clean.replace(/(?<=":[ ]*"[^"]*)\n(?=[^"]*")/g, '\\n');

const rawLength = clean.length;

let persona;
try {
  persona = JSON.parse(clean);
} catch(e) {
  try {
    const cleaned2 = clean
      .replace(/[\x00-\x1F\x7F]/g, ' ')
      .replace(/,\s*}/g, '}')
      .replace(/,\s*\]/g, ']');
    persona = JSON.parse(cleaned2);
  } catch(e2) {
    throw new Error('JSON parse failed after 2 attempts. First 500 chars: ' + clean.substring(0, 500));
  }
}

// === VALIDATION ===
const required = [
  'persona_name', 'segment', 'demographics', 'jtbd', 'hunt_ladder',
  'search_behavior', 'aeo_profile', 'content_preferences', 'competitor_overlap', 'priority_score'
];
const missing = required.filter(f => !persona[f]);

const huntLevels = persona.hunt_ladder ? Object.keys(persona.hunt_ladder).length : 0;
const hasAEO = persona.aeo_profile?.ai_platforms?.length > 0;
const scoreValid = persona.priority_score >= 1 && persona.priority_score <= 100;
const hasBarriers = persona.jtbd?.barriers?.length > 0;
const hasTriggers = persona.jtbd?.triggers?.length > 0;
const hasCommercial = !!persona.commercial_factors;

// Weighted QC scoring (rule-based)
let qc_score = 100;
const issues = [];

if (missing.length > 0) { qc_score -= (missing.length * 8); issues.push('Missing fields: ' + missing.join(', ')); }
if (!hasTriggers) { qc_score -= 12; issues.push('No JTBD triggers'); }
if (!hasBarriers) { qc_score -= 12; issues.push('No JTBD barriers'); }
if (huntLevels < 5) { qc_score -= 20; issues.push(`Only ${huntLevels}/5 Hunt levels`); }
if (!hasAEO) { qc_score -= 15; issues.push('No AEO data'); }
if (!persona.demographics?.age_range) { qc_score -= 8; issues.push('No age_range'); }
if (!scoreValid) { qc_score -= 8; issues.push('Invalid priority_score'); }
if (rawLength < 3000) { qc_score -= 20; issues.push(`Too short: ${rawLength} chars`); }
else if (rawLength < 4000) { qc_score -= 10; issues.push(`Short: ${rawLength} chars`); }
if (!hasCommercial) { qc_score -= 5; issues.push('No commercial_factors'); }

// Check query count per Hunt level
let totalQueries = 0;
if (persona.hunt_ladder) {
  Object.entries(persona.hunt_ladder).forEach(([level, data]) => {
    const queries = data?.sample_queries?.length || 0;
    totalQueries += queries;
    if (queries < 3) { qc_score -= 3; issues.push(`${level}: only ${queries} queries`); }
  });
}

// Check [Я]/[G] engine tagging
let engineTagged = 0, engineTotal = 0;
if (persona.hunt_ladder) {
  Object.values(persona.hunt_ladder).forEach(level => {
    if (level.sample_queries) {
      level.sample_queries.forEach(q => {
        engineTotal++;
        if (typeof q === 'object' && q.engine) engineTagged++;
      });
    }
  });
}
if (engineTotal > 0 && engineTagged < engineTotal * 0.5) {
  qc_score -= 5; issues.push(`Engine tagging: only ${engineTagged}/${engineTotal} queries tagged`);
}

qc_score = Math.max(0, Math.min(100, qc_score));
const status = qc_score >= 80 ? 'ready' : (qc_score >= 60 ? 'review' : 'poor');

const allQueries = [];
if (persona.hunt_ladder) {
  Object.values(persona.hunt_ladder).forEach(level => {
    if (level.sample_queries) {
      level.sample_queries.forEach(q => {
        allQueries.push(typeof q === 'object' ? q.query : q);
      });
    }
  });
}

// ML features for prediction
const ml_features = {
  text_length: rawLength,
  hunt_levels: huntLevels,
  total_queries: totalQueries,
  has_aeo: hasAEO ? 1 : 0,
  has_commercial: hasCommercial ? 1 : 0,
  rag_sources: ragInfo.sources_count || 0,
  triggers_count: (persona.jtbd?.triggers || []).length,
  barriers_count: (persona.jtbd?.barriers || []).length,
  missing_fields: missing.length,
  engine_tagged_pct: engineTotal > 0 ? engineTagged / engineTotal : 0
};

return [{ json: {
  persona,
  persona_name: persona.persona_name || '',
  segment: persona.segment || '',
  niche: inp.niche, city: inp.city,
  target_audience_type: inp.target_audience_type,
  project_id: inp.project_id, domain: inp.domain,
  niche_cluster: inp.niche_cluster,
  priority_engines: inp.priority_engines,
  deterministic_id: inp.deterministic_id,
  priority_score: persona.priority_score || 50,
  qc_score, rule_qc_score: qc_score, status, issues: issues.length > 0 ? issues : null,
  main_jtbd: persona.jtbd?.core_job || '',
  problems_summary: persona.jtbd?.emotional_job || '',
  top_queries: allQueries.slice(0, 15),
  total_queries: totalQueries,
  hunt_ladder_levels: huntLevels,
  triggers_count: (persona.jtbd?.triggers || []).length,
  barriers_count: (persona.jtbd?.barriers || []).length,
  preferred_formats: persona.content_preferences?.preferred_formats || [],
  ai_platforms: persona.aeo_profile?.ai_platforms || [],
  has_aeo: !!hasAEO,
  has_commercial: hasCommercial,
  rag_sources_used: ragInfo.sources_count || 0,
  rag_top_score: ragInfo.top_score || 0,
  rag_quality: ragInfo.rag_quality || 'empty',
  uses_ai_search: persona.aeo_profile?.uses_ai_search || false,
  groq_tokens: tokens, model_used, latency_ms,
  embed_text: `${inp.niche} ${inp.city} ${persona.persona_name||''} ${persona.jtbd?.core_job||''} ${persona.jtbd?.emotional_job||''}`,
  prompt_version: promptInfo.prompt_version,
  raw_content_length: rawLength,
  log_id: llmPrep.log_id,
  attempt: llmPrep.attempt || 1,
  ml_features,
  engine_tagged: engineTagged,
  engine_total: engineTotal
}}];

