const extracted = $('Extract & Validate JSON').first().json;
let ml_qc = null, ml_available = false;

try {
  const mlResult = $('ML Predict Quality').first().json;
  if (mlResult && mlResult.prediction !== undefined) {
    ml_qc = Math.round(mlResult.prediction * 100);
    ml_available = true;
  }
} catch(e) {}

// Merge: ML available → weighted average, otherwise rule-based only
let final_qc;
if (ml_available && ml_qc !== null) {
  final_qc = Math.round(extracted.rule_qc_score * 0.4 + ml_qc * 0.6);
} else {
  final_qc = extracted.rule_qc_score;
}

final_qc = Math.max(0, Math.min(100, final_qc));
const final_status = final_qc >= 80 ? 'ready' : (final_qc >= 60 ? 'review' : 'poor');

return [{ json: {
  ...extracted,
  qc_score: final_qc,
  ml_qc_score: ml_qc,
  ml_available,
  status: final_status,
  qc_method: ml_available ? 'ml+rule hybrid' : 'rule-based only'
}}];

const data = $input.first().json;
const attempt = data.attempt || 1;
const qc = data.qc_score;

if (qc < 60 && attempt < 3) {
  // RETRY: rotate A/B strategy and try again
  return [{
    json: {
      ...data,
      retry: true,
      next_attempt: attempt + 1,
      retry_reason: `QC ${qc}/100 on attempt ${attempt}, trying strategy rotation`
    }
  }];
} else {
  // PROCEED: either good enough or max retries reached
  const is_best = !data.best_persona || qc > (data.best_qc || 0);
  return [{
    json: {
      ...data,
      retry: false,
      is_final: true,
      final_note: qc >= 60 
        ? `QC ${qc}/100 passed on attempt ${attempt}` 
        : `QC ${qc}/100 after ${attempt} attempts (max retries reached)`
    }
  }];
}

const data = $input.first().json;
const inp = $('Validate & Normalize Input').first().json;

// Update attempt counter and pass back to Build Prompt
return [{ json: {
  ...inp,
  attempt: data.next_attempt,
  best_qc: Math.max(data.best_qc || 0, data.qc_score),
  best_persona: (data.qc_score > (data.best_qc || 0)) ? data.persona : data.best_persona,
  retry_reason: data.retry_reason
}}];
